+# but WITHOUT ANY WARRANTY; without even the implied warranty of
+# MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.  See the
+# GNU General Public License for more details.
+#
+# You should have received a copy of the GNU General Public License
+# along with this program; if not, write to the Free Software
+# Foundation, Inc., 59 Temple Place, Suite 330, Boston, MA  02111-1307  USA
+#
+# Version: 1.3
+# This plugin currently supports :=20
+# "mirror", "stripe", "raid3", "concat", and "shsec" GEOM classes.
+# With a bit of fondling, it could be expanded to recognize other classes
+#
+# Usage:   check_geom <geom class> <volume>
+# Example: check_geom mirror gm0
+#          WARNING gm0 DEGRADED, { ad0 , ad1 (32%) }
+
+use strict;
+
+my %ERRORS=3D('DEPENDENT'=3D>4,'UNKNOWN'=3D>3,'OK'=3D>0,'WARNING'=3D>1,'CR=
ITICAL'=3D>2);
+my $state=3D"UNKNOWN";
+my $msg=3D"FAILURE";
+
+if ($#ARGV < 1) {
+	print "Not enough arguments!\nUsage: $0 <class> <device>\n";
+	exit $ERRORS{$state};
+}
+
+if ($^O ne 'freebsd') {
+	print "This plugin is only applicable on FreeBSD.\n";
+	exit $ERRORS{$state};
+}
+
+my $class=3D$ARGV[0];
+my $volume=3D$ARGV[1];
+my $statcommand=3D"geom $class status";
+
+if (! open STAT, "$statcommand|") {
+	print ("$state $statcommand returns no result!");
+	exit $ERRORS{$state};
+}
+
+my $found=3D0;
+my $unit=3D0;
+my $status=3D"";
+my $name=3D"";
+my $compo=3D"";
+
+while(<STAT>) {
+
+	chomp;
+	if ($found) {
+		if (/^\s*$class\//) {
+			last;
+		} else {
+			my ($vgh) =3D /\s+(.*)/;
+			$compo=3D"$compo , $vgh";
+			$found++;
+		}
+	}
+
+	if (/^\s*$class\/$volume\s/) {
+		($name, $status, $compo) =3D /(\S+)\s+(\S+)\s+(.*)$/;
+		$found=3D1;
+	}
+=09
+}
+
+close(STAT);
+
+if (! $found ) {
+	$state =3D "CRITICAL";
+	$msg =3D sprintf "%s/%s does not exist and/or is not responding!\n", $cla=
ss, $volume;
+	print $state, " ", $msg;
+	exit ($ERRORS{$state});
+}
+
+if (($class eq "mirror" || $class eq "raid3") && $status =3D~ /COMPLETE/ )=
 {
+		$state =3D "OK";
+}
+
+if ($class eq "stripe" || $class eq "concat" || $class eq "shsec" && $stat=
us =3D~ /UP/) {
+		$state =3D "OK";
+}
+
+if ($state ne "OK") {
+
+	if ($class eq "mirror" && $found >=3D 2 ) {
+		$state =3D "WARNING";
+	} else {
+		$state =3D "CRITICAL";
+	}
+
+	if ($class eq "raid3") {
+=09
+		$statcommand=3D"geom $class list $volume";
+	=09
+		if (! open STAT, "$statcommand|") {
+			print ("$state $statcommand returns no result!");
+			exit $ERRORS{$state};
+		}
+
+		while (<STAT>) {
+			next unless (/Components:/);
+			($unit) =3D /([0-9]+)$/;
+			next;
+		}
+
+		if ($found =3D=3D $unit) {
+			$state =3D "WARNING";
+		}
+
+	}
+}
+
+#goats away!
+$msg =3D sprintf "%s/%s %s { %s }\n", $class, $volume, $status, $compo;
+print $state, " ", $msg;
+exit ($ERRORS{$state});
